import requests
url = "https://movie.douban.com/top250"
headers = {"User-Agent":"Chrome浏览器UA字符串"}
try:
    res = requests.get(url, headers=headers, timeout=10)
    res.encoding = "utf-8"
    if res.status_code == 200:
        print(res.text[:500])
    else:
        print(f"请求失败：{res.status_code}")
except requests.Timeout:
    print("请求超时")

