import scrapy
class BookSpider(scrapy.Spider):
    name = "book"
    start_urls = ["http://books.example.com/list"]
    def parse(self, resp):
        books = resp.css("div.book-item")
        for b in books:
            yield {"book_name":b.css("h3.title::text").get(),"author":b.css("span.author::text").get()}
        next_url = resp.css("a.next::attr(href)").get()
        if next_url:
            yield resp.follow(next_url, callback=self.parse)
